var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"젠장…!","JPN":"くそ……！","ENG":"Dammit...!","TWN":"該死……！"},"stage":{"bg":"SWORDGRAVE_STAR","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"여기까지 어떻게 왔는데…! 고작 몇 걸음 남았단 말이다!","JPN":"やっとここまで来れたのに……！　あと数歩のところだったのに！","ENG":"We were this close...! Just a couple more steps!","TWN":"好不容易才走到這裡……！就差幾步了！"},"stage":{"bg":"SWORDGRAVE_STAR","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"이것도 망할 운명이란 거냐? 탐미엘! 언제까지 이딴 희망고문만 할 셈이야!","JPN":"これも運命ってやつなの？　タミエル！　いつまでこんなことを続けるつもりなんだ！","ENG":"Are you saying this is fate too? Tammiel! How much longer are you going to give us false hope like this?!","TWN":"這也是該死的命運嗎？塔米爾！你打算一直這樣用希望來折磨我嗎！"},"stage":{"bg":"SWORDGRAVE_STAR","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SWORDGRAVE_STAR","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"검이… 빛나고 있어?","JPN":"剣が……光ってる？","ENG":"The sword... it's glowing?","TWN":"斷劍……在發光？"},"stage":{"bg":"SWORDGRAVE_STAR","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SYS_ARC_NULL_NULL","text":{"KOREA":"관리 권한자 접근을 확인했습니다.","JPN":"管理権限者の接近を確認しました。","ENG":"Supervisor confirmed.","TWN":"確認管理許可權者接入。"},"stage":{"bg":"MAINSTREAM_000002","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SYS_ARC_NULL_NULL","text":{"KOREA":"임시 동결 해제. 시스템 온라인.","JPN":"臨時凍結を解除。システムオン。","ENG":"Temporary cryostasis, disabled. System online.","TWN":"臨時凍結解除。系統，上線。"},"stage":{"bg":"MAINSTREAM_000004","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SYS_ARC_NULL_NULL","text":{"KOREA":"용무가 있으십니까?","JPN":"何のご用でしょうか？","ENG":"May I help you?","TWN":"需要什麼協助？"},"stage":{"bg":"MAINSTREAM_000004","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"내가 여기서 지낸 뒤로… 시간이 얼마나 지났죠?","JPN":"私がここで過ごして……どれぐらい経ちましたか？","ENG":"How long has it been... since I've been here?","TWN":"我……在這裡待多久了？"},"stage":{"bg":"MAINSTREAM_000004","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SYS_ARC_NULL_NULL","text":{"KOREA":"이 장소는 방주의 동결 프로세스에 의해 모든 것이 멈춰있습니다.","JPN":"この場所は箱舟の凍結プロセスによってすべてが停止しています。","ENG":"Everything here has been stopped by the Ark's cryostasis protocol.","TWN":"目前這個空間的一切因為方舟的凍結保存協議而停滯了。"},"stage":{"bg":"MAINSTREAM_000004","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SYS_ARC_NULL_NULL","text":{"KOREA":"따라서 시간을 정의하는 것은 무의미합니다.","JPN":"よって、時間を定義することは無意味です。","ENG":"Thus, defining time here is meaningless.","TWN":"因此，在這裡定義時間是沒有意義的。"},"stage":{"bg":"MAINSTREAM_000004","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SYS_ARC_NULL_NULL","text":{"KOREA":"권한자께서 사고하고 행동할 수 있는 이유는 이 세계를 정의하는 개념 그 자체이기 때문에 가능한 일입니다.","JPN":"権限者様が思考し、行動できるのは、この世界を定義する概念そのものだからです。","ENG":"The reason why you are still able to think and act is because you are the very concept that defines this world.","TWN":"許可權者之所以能夠思考和行動，是因為她本身就是定義這個世界的概念。"},"stage":{"bg":"MAINSTREAM_000004","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"바깥에선… 얼마나 많은 시간이 흘렀나요?","JPN":"では外の世界では……どれぐらいの時間が経っていますか？","ENG":"How much time has passed... out there?","TWN":"外面……已經過了多久了？"},"stage":{"bg":"MAINSTREAM_000004","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SYS_ARC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MAINSTREAM_000004","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SYS_ARC_NULL_NULL","text":{"KOREA":"본함은 현재 공간 외부의 테라브레인과 동기화되어 있지 않아 그 질문에 정확한 답을 드리기 어렵습니다.","JPN":"本艦は現在、空間外部のテラブレインと同期していないため、その質問には答えられません。","ENG":"It is difficult to answer your question as this ship is currently not synced with Terrabrain outside of space.","TWN":"本艦目前未與空間外部的特拉大腦同步，因此很難準確回答你的問題。"},"stage":{"bg":"VOID","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SYS_ARC_NULL_NULL","text":{"KOREA":"하지만, 동결 범위 바깥에 존재하는 천체의 변화를 동결 전후로 비교했을 때…","JPN":"しかし、凍結範囲外に存在する天体の変化を、凍結前と比較すると……","ENG":"However, by calculating the difference in the changes in celestial bodies outside the cryostasis range...","TWN":"但是，透過計算凍結範圍之外天體在凍結前後的變化……"},"stage":{"bg":"VOID","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SYS_ARC_NULL_NULL","text":{"KOREA":"약 1억 6천 만 년 가량이 경과한 것으로 추정됩니다.","JPN":"およそ1億6千万年が経過していると推定されます。","ENG":"it is estimated that about 160 million years have passed.","TWN":"預估已經過了1億6千萬年。"},"stage":{"bg":"VOID","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"스승님의 시간도… 그만큼 흘렀을까요?","JPN":"師匠の時間も……それぐらい経っているんでしょうか？","ENG":"Has that much time... also passed for Master?","TWN":"師父的時間……也流逝了這麼久嗎？"},"stage":{"bg":"VOID","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SYS_ARC_NULL_NULL","text":{"KOREA":"시간은 상대적입니다. 차원 간 시차는 은하와 은하 사이의 간극보다 더 불규칙적이기 때문에 간단히 정의 내리기 어렵습니다.","JPN":"時間は相対的なものです。次元間の時差は、銀河と銀河の時差よりも不規則なものであるため、一言で定義することは難しいです。","ENG":"Time is relative. Interdimensional parallax is difficult to define as it is more irregular than the gap between galaxies.","TWN":"時間是相對的。次元間的時差比銀河與銀河之間的間隙更不規則，因此很難簡單定義。"},"stage":{"bg":"VOID","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SYS_ARC_NULL_NULL","text":{"KOREA":"어쩌면 이곳보다 더 많은 시간이 흘렀을 수도 있고, 하루가 흘렀을 수도 있습니다.","JPN":"ここより長い時間が経っている可能性も、一日しか経っていない可能性もあります。","ENG":"More time could have passed than here, or perhaps only a day.","TWN":"也許那裡已經過了很長時間，也可能只過了一天。"},"stage":{"bg":"VOID","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"…그러면 말이죠.","JPN":"じゃあ……","ENG":"...Then.","TWN":"……這麼說的話。"},"stage":{"bg":"MAINSTREAM_000004","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"제가 스승님의 운명을 이용해 시간을 흐르게 해도… 이제 괜찮은 걸까요?","JPN":"もう……師匠の運命を使って、時間を動かしても……いいんでしょうか？","ENG":"Would it be okay... to use Master's fate to make time flow now?","TWN":"即使現在我用師父的命運讓時間流逝……也沒關係了嗎？"},"stage":{"bg":"MAINSTREAM_000004","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SYS_ARC_NULL_NULL","text":{"KOREA":"모든 결정 권한은 권한자께 부여되어 있습니다.","JPN":"すべての決定への権限は、権限者様にあります。","ENG":"All authority has been granted to you.","TWN":"所有決策許可權均已授予許可權者。"},"stage":{"bg":"MAINSTREAM_000004","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SYS_ARC_NULL_NULL","text":{"KOREA":"권한자께서 원하신다면 본함은 그 결정에 따라 격리를 해제할 뿐입니다.","JPN":"権限者様が望むのであれば、本艦はその決定に従い、隔離を解除します。","ENG":"If that is what you want, the ship will lift the isolation accordingly.","TWN":"如果許可權者希望，本艦將根據你的決定解除隔離。"},"stage":{"bg":"MAINSTREAM_000004","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MAINSTREAM_000004","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"L51_1","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"L51_1","face":"L51_1"},"R":null}}}]`);export{e as default};